          "            reader = csv.DictReader(io.StringIO(input_text.strip()))",
          "            rows = list(reader)",
          "            result = json.dumps(rows, indent=2, ensure_ascii=False)",
          "        else:",
          "            data = json.loads(input_text)",
          "            if not isinstance(data, list): data = [data]",
          "            output = io.StringIO()",
          "            if data:",
